const input = $input.first().json;
const payload = input.payload ?? input;
const sensitive = ['send_email', 'delete_email', 'forward_email'];
if (!payload.action) return [{ json: { status: 'error', result: {}, approval_required: false, error: 'action is required' } }];
if (sensitive.includes(payload.action)) return [{ json: { status: 'pending_approval', result: { draft: { recipient: payload.recipient, subject: payload.subject, body: payload.body } }, approval_required: true } }];
return [{ json: { status: 'success', result: { action: payload.action, query: payload.query ?? null, note: 'Email provider credential placeholder. Configure Gmail/SMTP before production.' }, approval_required: false } }];
